SELECT ?artist ?artistLabel ?unitsSold WHERE {
  ?artist wdt:P106 wd:Q2771295 ;
          wdt:P135 ?genre ;
          wdtn:P2664 ?unitsSold .
  ?genre wdt:P279* wd:Q45981 .
  ?artist rdfs:label ?artistLabel .
  FILTER (lang(?artistLabel) = 'en')
} ORDER BY DESC(?unitsSold) LIMIT 1

